firestore.rules:
rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check login
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper function to fetch user record role
    function getUserRole() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role;
    }

    // 1. Users collection rules
    match /users/{userId} {
      allow read: if isSignedIn();
      allow write: if isSignedIn() && (request.auth.uid == userId || getUserRole() == 'admin');
    }

    // 2. Students collection rules
    match /students/{studentId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn() && request.auth.uid == studentId;
      allow update: if isSignedIn() && (request.auth.uid == studentId || getUserRole() == 'admin');
      allow delete: if isSignedIn() && getUserRole() == 'admin';
    }

    // 3. Recruiters collection rules
    match /recruiters/{recruiterId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn() && request.auth.uid == recruiterId;
      allow update, delete: if isSignedIn() && (request.auth.uid == recruiterId || getUserRole() == 'admin');
    }

    // 4. Companies collection rules
    match /companies/{companyId} {
      allow read: if isSignedIn();
      allow write: if isSignedIn() && (request.auth.uid == companyId || getUserRole() == 'admin');
    }

    // 5. Jobs collection rules
    match /jobs/{jobId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn() && (getUserRole() == 'recruiter' || getUserRole() == 'admin');
      allow update, delete: if isSignedIn() && (resource.data.recruiterId == request.auth.uid || getUserRole() == 'admin');
    }

    // 6. Applications collection rules
    match /applications/{appId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn() && getUserRole() == 'student';
      allow update: if isSignedIn() && (getUserRole() == 'recruiter' || getUserRole() == 'admin');
      allow delete: if isSignedIn() && getUserRole() == 'admin';
    }

    // 7. Interviews collection rules
    match /interviews/{interviewId} {
      allow read: if isSignedIn();
      allow write: if isSignedIn() && (getUserRole() == 'recruiter' || getUserRole() == 'admin');
    }

    // 8. Notifications collection rules
    match /notifications/{notifId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      allow update: if isSignedIn() && (resource.data.userId == request.auth.uid || resource.data.userId == 'all');
      allow delete: if isSignedIn() && getUserRole() == 'admin';
    }

    // 9. Placement Drives collection rules
    match /placement_drives/{driveId} {
      allow read: if isSignedIn();
      allow write: if isSignedIn() && getUserRole() == 'admin';
    }
  }
},
  "storage": {
    "rules": "rules_version = '2';

service firebase.storage {
  match /b/{bucket}/o {
    match /resumes/{fileName} {
      // Allow anyone logged in to view/download resumes (for recruiters and admins)
      allow read: if request.auth != null;

      // Allow students to upload PDF resumes under 2MB, naming the file as {studentUid}_*.pdf
      allow write: if request.auth != null 
                   && request.resource.contentType == 'application/pdf'
                   && request.resource.size < 2 * 1024 * 1024;
    }
  }
}"
  }
}
